// Заглушка для теста WF_EVENT_UPSERT_MANUAL без Telegram и агентів
// Повертаємо один item з полями, які очікує PG.UPSERT_EVENT.

return [
  {
    json: {
      src_title: 'Нове забруднення мазутом уздовж узбережжя Чорного моря',
      src_url: 'https://en.iz.ru/en/1828496/2025-01-26/new-fuel-oil-emissions-were-recorded-black-sea-coastline',
      // дата події (коли реально сталось) — з твоєго прикладу: 2024-01-26
      event_date: '2024-01-26',
      // короткий український summary (можеш переформулювати як хочеш)
      short_summary: 'У січні 2024 року зафіксовано нові викиди мазуту на 17 ділянках узбережжя Чорного моря. Забруднено понад 63 км берегової лінії, залучено фахівців та волонтерів до очищення та моніторингу акваторії.',
      // координати для тесту можна залишити null
      lat: null,
      lon: null,
      // довільні нотатки для поля llm_extract.manual.notes
      notes: 'test stub from CODE.TEST_STUB'
    }
  }
];

const rows = $input.all().map(i => i.json);
return [{
  json: {
    events: rows,
    message: rows.length
      ? `Додано/оновлено ${rows.length} подію(ї) в базі.`
      : 'Подія не була змінена.'
  }
}];
